(function(global){
  class SimpleSwiper {
    constructor(selector, params){
      this.params = Object.assign({
        initialSlide: 0,
        threshold: 40,
        noSwipingSelector: null,
        on: {}
      }, params || {});
      this.container = typeof selector === 'string' ? document.querySelector(selector) : selector;
      if (!this.container) {
        throw new Error('Swiper container not found');
      }
      this.wrapper = this.container.querySelector('.swiper-wrapper') || this.container.firstElementChild;
      if (!this.wrapper) {
        throw new Error('Swiper wrapper not found');
      }
      this.slides = Array.from(this.wrapper.children);
      this.events = this.params.on || {};
      this.activeIndex = 0;
      this.isDragging = false;
      this.allowTouchMove = true;
      this.startX = 0;
      this.startY = 0;
      this.currentX = 0;
      this.touchStartTime = 0;
      this.wrapper.style.transition = 'transform 0.3s ease';
      this.wrapper.style.willChange = 'transform';
      this.init();
    }

    init(){
      const initial = Math.min(Math.max(parseInt(this.params.initialSlide, 10) || 0, 0), this.slides.length - 1);
      this.slideTo(initial, false);
      this.attachEvents();
      this.emit('afterInit', this);
    }

    getContainerWidth(){
      const width = this.container.clientWidth || this.container.getBoundingClientRect().width;
      return width || 1;
    }

    attachEvents(){
      this.onTouchStart = this.handleTouchStart.bind(this);
      this.onTouchMove = this.handleTouchMove.bind(this);
      this.onTouchEnd = this.handleTouchEnd.bind(this);
      this.wrapper.addEventListener('touchstart', this.onTouchStart, { passive: false });
      this.wrapper.addEventListener('touchmove', this.onTouchMove, { passive: false });
      this.wrapper.addEventListener('touchend', this.onTouchEnd, { passive: true });
      this.wrapper.addEventListener('mousedown', this.onTouchStart);
      document.addEventListener('mousemove', this.onTouchMove);
      document.addEventListener('mouseup', this.onTouchEnd);
    }

    destroy(){
      this.wrapper.removeEventListener('touchstart', this.onTouchStart);
      this.wrapper.removeEventListener('touchmove', this.onTouchMove);
      this.wrapper.removeEventListener('touchend', this.onTouchEnd);
      this.wrapper.removeEventListener('mousedown', this.onTouchStart);
      document.removeEventListener('mousemove', this.onTouchMove);
      document.removeEventListener('mouseup', this.onTouchEnd);
    }

    handleTouchStart(evt){
      if (evt.type === 'mousedown' && evt.button !== 0) {
        return;
      }
      const touch = evt.touches ? evt.touches[0] : evt;
      if (!touch) return;
      if (this.params.noSwipingSelector) {
        const target = evt.target;
        if (target && target.closest && target.closest(this.params.noSwipingSelector)) {
          this.allowTouchMove = false;
          return;
        }
      }
      this.allowTouchMove = true;
      this.isDragging = true;
      this.startX = touch.clientX;
      this.startY = touch.clientY;
      this.currentX = this.startX;
      this.touchStartTime = Date.now();
      if (this.params.touchStartPreventDefault !== false && evt.cancelable) {
        evt.preventDefault();
      }
    }

    handleTouchMove(evt){
      if (!this.isDragging || !this.allowTouchMove) {
        return;
      }
      const touch = evt.touches ? evt.touches[0] : evt;
      if (!touch) return;
      const deltaX = touch.clientX - this.startX;
      const deltaY = touch.clientY - this.startY;
      if (Math.abs(deltaY) > Math.abs(deltaX)) {
        this.isDragging = false;
        return;
      }
      if (evt.cancelable) {
        evt.preventDefault();
      }
      this.currentX = touch.clientX;
      const width = this.getContainerWidth();
      const translate = -this.activeIndex * width + deltaX;
      this.wrapper.style.transition = 'none';
      this.setTranslate(translate);
    }

    handleTouchEnd(evt){
      if (!this.isDragging) {
        return;
      }
      this.isDragging = false;
      this.wrapper.style.transition = 'transform 0.3s ease';
      if (!this.allowTouchMove) {
        this.slideTo(this.activeIndex);
        return;
      }
      const touch = evt.changedTouches ? evt.changedTouches[0] : evt;
      if (!touch) {
        this.slideTo(this.activeIndex);
        return;
      }
      const deltaX = touch.clientX - this.startX;
      const deltaY = touch.clientY - this.startY;
      const absDeltaX = Math.abs(deltaX);
      const absDeltaY = Math.abs(deltaY);
      const timeDiff = Date.now() - this.touchStartTime;
      const threshold = Number(this.params.threshold) || 40;
      const longSwipe = timeDiff > (this.params.longSwipesMs || 200);
      const width = this.getContainerWidth();
      const ratio = Math.abs(deltaX) / width;

      if (absDeltaY > absDeltaX) {
        this.slideTo(this.activeIndex);
        return;
      }

      if (absDeltaX > threshold || (longSwipe && ratio > (this.params.longSwipesRatio || 0.1))) {
        if (deltaX < 0 && this.activeIndex < this.slides.length - 1) {
          this.slideTo(this.activeIndex + 1);
          return;
        }
        if (deltaX > 0 && this.activeIndex > 0) {
          this.slideTo(this.activeIndex - 1);
          return;
        }
      }
      this.slideTo(this.activeIndex);
    }

    setTranslate(px){
      this.wrapper.style.transform = `translate3d(${px}px, 0, 0)`;
    }

    slideTo(index, emitEvent = true){
      const newIndex = Math.min(Math.max(index, 0), this.slides.length - 1);
      this.activeIndex = newIndex;
      const width = this.getContainerWidth();
      const offset = -newIndex * width;
      this.wrapper.style.transition = this.wrapper.style.transition || 'transform 0.3s ease';
      this.setTranslate(offset);
      this.updateSlideClasses();
      if (emitEvent) {
        this.emit('slideChange');
      }
    }

    updateSlideClasses(){
      this.slides.forEach((slide, idx) => {
        slide.classList.toggle('swiper-slide-active', idx === this.activeIndex);
        slide.classList.toggle('swiper-slide-prev', idx === this.activeIndex - 1);
        slide.classList.toggle('swiper-slide-next', idx === this.activeIndex + 1);
      });
    }

    emit(eventName, ...args){
      const handler = this.events[eventName];
      if (typeof handler === 'function') {
        handler.apply(this, args.length ? args : [this]);
      }
    }

    next(){
      if (this.activeIndex < this.slides.length - 1) {
        this.slideTo(this.activeIndex + 1);
      }
    }

    prev(){
      if (this.activeIndex > 0) {
        this.slideTo(this.activeIndex - 1);
      }
    }
  }

  global.Swiper = SimpleSwiper;
})(typeof window !== 'undefined' ? window : this);
